(3, 'What do you most want to protect in this world?\n---\nProtective instincts reveal our deepest values.\n• A person, a place, an idea, a way of being\n• What is it?\n• What threatens it?', NULL, '{}', 'protection', 'feeling', '{answered_10+}', 'want_to_protect', '{protection,values}', 433),
(3, 'If your life had a soundtrack, what would be playing right now?\n---\nLife in musical terms.\n• Loud or quiet, fast or slow\n• Different chapters, different genres\n• What song belongs to the most important scene?', NULL, '{}', 'creative', 'feeling', '{answered_10+}', 'life_soundtrack', '{creative,identity}', 434),
(3, 'When did you receive love you didn''t recognize until later?\n---\nSome love arrives in disguise.\n• Tough love, space when you wanted closeness\n• What was the gesture?\n• When did you finally understand?', NULL, '{}', 'love', 'feeling', '{answered_10+}', 'delayed_love', '{love,recognition}', 435),
(3, 'What''s the most generous interpretation of your hardest year?\n---\nTell the story with compassion for yourself.\n• What were you dealing with?\n• What did surviving it prove?\n• What would kindness see?', NULL, '{}', 'reframing', 'turning_point', '{answered_10+}', 'generous_interpretation', '{reframing,resilience}', 436),
(3, 'What does your silence communicate?\n---\nQuiet speaks volumes.\n• Processing, protecting, withdrawing, something else\n• What would someone need to understand?\n• What''s really going on?', NULL, '{}', 'communication', 'feeling', '{answered_10+}', 'silence_meaning', '{communication,inner_world}', 437),
(3, 'When were you loved in a way you didn''t feel you deserved?\n---\nGrace in love is hard to accept.\n• In a dark place, after mistakes, couldn''t give back equally\n• What was the love, who gave it?\n• What did accepting it do?', NULL, '{}', 'grace', 'feeling', '{answered_10+}', 'undeserved_love', '{grace,acceptance}', 438),
(3, 'If the walls of your childhood home could talk, what would they say?\n---\nWalls witness everything.\n• Not just your story, the whole family''s\n• What happened in those rooms?\n• What would they know that nobody said?', NULL, '{}', 'childhood', 'place', '{answered_10+}', 'walls_talking', '{childhood,home,secrets}', 439),
(3, 'What do you wish you could explain to the people who love you?\n---\nSome things resist words.\n• How you process things, what you need\n• What this stretch of life feels like\n• What would you say if language cooperated?', NULL, '{}', 'communication', 'feeling', '{answered_10+}', 'cant_explain', '{communication,frustration}', 440),
(3, 'When did the world feel small in a beautiful way?\n---\nCoincidence can feel like magic.\n• Ran into someone, discovered a connection\n• Realized how linked everything is\n• What happened?', NULL, '{}', 'wonder', 'feeling', '{answered_10+}', 'small_world', '{wonder,connection}', 441),
(3, 'What about your inner life would surprise the people closest to you?\n---\nEven loved ones miss things.\n• They think they know you fully\n• But there''s a room they haven''t entered\n• What''s in it?', NULL, '{}', 'hidden', 'feeling', '{answered_10+}', 'inner_surprise', '{hidden,depth}', 442),
(3, 'What have you learned about loss that you wish you''d known before?\n---\nLoss teaches its own curriculum.\n• How grief works, what it asks of you\n• How it changes shape without leaving\n• What do you know now?', NULL, '{}', 'loss', 'feeling', '{answered_10+}', 'loss_wisdom', '{loss,wisdom}', 443),
(3, 'How has what "home" means to you changed over the years?\n---\nHome is a shifting definition.\n• Expanded, shifted, built rather than inherited\n• What did it mean then?\n• What does it mean now?', NULL, '{}', 'evolution', 'feeling', '{answered_10+}', 'home_evolution', '{evolution,maturity}', 444),
(3, 'What would you most want to hear from someone you''ve lost?\n---\nSome words would change everything.\n• Permission, forgiveness, a joke, just your name\n• What would they say?\n• What would those words give you?', NULL, '{}', 'grief', 'people', '{answered_10+}', 'want_to_hear', '{grief,longing}', 445),
(3, 'What about you has stayed the same no matter how much else changed?\n---\nEveryone has a constant.\n• A value, a quirk, a way of seeing things\n• What''s your constant?\n• Are you glad it stayed?', NULL, '{}', 'core', 'feeling', '{answered_10+}', 'constant_self', '{core,identity}', 446),
(3, 'What simple pleasure has become almost sacred to you?\n---\nSome small things feel essential.\n• A morning cup, a walk, a weekly call, a few minutes of quiet\n• What is it?\n• What happens inside you during that time?', NULL, '{}', 'sacred', 'event', '{answered_10+}', 'sacred_pleasure', '{sacred,routine}', 447),
(3, 'What''s the space between who you were and who you are now?\n---\nA canyon or a footbridge?\n• How did you cross from one to the other?\n• What did you bring with you?\n• What did you leave behind?', NULL, '{}', 'integration', 'turning_point', '{answered_10+}', 'bridging_selves', '{integration,identity}', 448),
(3, 'How are you still your parents'' child, no matter how old you get?\n---\nSome threads never break.\n• How you react under pressure, what comforts you\n• A habit you thought you''d outgrow\n• What ties you to being someone''s kid?', NULL, '{}', 'family', 'people', '{answered_10+}', 'still_their_child', '{family,permanence}', 449),
(3, 'What''s the most important promise you''ve ever made?\n---\nPromises shape the lives we build.\n• To yourself, someone else, or something bigger\n• When did you make it?\n• How has keeping it shaped your life?', NULL, '{}', 'promises', 'feeling', '{answered_10+}', 'important_promise', '{promises,commitment}', 450);
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(4, 'What thread runs through all the memories you''ve shared?\n---\nPatterns emerge when you look back.\n• A person who keeps appearing, a recurring feeling\n• A value you keep circling back to\n• What does the pattern reveal?', NULL, '{}', 'synthesis', 'turning_point', '{answered_20+}', 'common_thread', '{synthesis,pattern}', 451),
(4, 'What would the next generation need to know to really understand you?\n---\nNot your resume, the essential thing.\n• What would they need to know?\n• What would surprise them?\n• What do you most want to pass on?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'grandchildren_know', '{legacy,essence}', 452),
(4, 'What would you title this current chapter of your life?\n---\nEvery chapter has a theme.\n• The central tension or joy right now\n• What''s the chapter about?\n• How close are you to the end of it?', NULL, '{}', 'narrative', 'turning_point', '{answered_20+}', 'chapter_title', '{narrative,framing}', 453),
(4, 'Is the story you tell yourself about your life the truest version?\n---\nWe all have a rehearsed narrative.\n• Overcoming, searching, building, holding on\n• Is there a more honest one underneath?\n• What would it sound like?', NULL, '{}', 'narrative', 'feeling', '{answered_20+}', 'self_narrative', '{narrative,truth}', 454),
(4, 'If you could leave one sentence behind for someone to find in a hundred years, what would it say?\n---\nDistill what you''ve learned.\n• What do you know that''s worth preserving?\n• Take your time with this one\n• Make every word count', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'one_sentence', '{legacy,distillation}', 455),
(4, 'What''s the central lesson your life keeps trying to teach you?\n---\nSome lessons show up in different forms.\n• Resisted it, embraced it, or still learning\n• What is it?\n• How has it appeared over the years?', NULL, '{}', 'wisdom', 'turning_point', '{answered_20+}', 'central_lesson', '{wisdom,pattern}', 456),
(4, 'If you were writing a memoir, what would the title be?\n---\nA title that captures the essence.\n• Not just events, the feeling of your life\n• What phrase or image tells the most?\n• Would people be surprised by your choice?', NULL, '{}', 'identity', 'feeling', '{answered_20+}', 'memoir_title', '{identity,self_image}', 457),
(4, 'What would you tell your twenty-year-old self in an hour together?\n---\nImagine sitting across from them.\n• What would you warn about, what reassurance do they need?\n• What question of theirs would be hardest to answer?\n• What would surprise them about now?', NULL, '{}', 'dialogue', 'people', '{answered_20+}', 'younger_self_convo', '{dialogue,time}', 458),
(4, 'What''s the most important thing you''ve learned about being human?\n---\nNot from a book, from living.\n• Something experience taught that theory couldn''t\n• What is it?\n• How did you earn it?', NULL, '{}', 'wisdom', 'feeling', '{answered_20+}', 'being_human', '{wisdom,universal}', 459),
(4, 'What keeps you going on the days when nothing feels like enough?\n---\nEveryone has something that gets them through.\n• A person, a promise, a habit, stubborn refusal\n• What is it?\n• Is it always the same thing?', NULL, '{}', 'resilience', 'feeling', '{answered_20+}', 'what_sustains', '{resilience,motivation}', 460),
(4, 'What do you want your life to have meant?\n---\nNot accomplishments, the actual mark.\n• What do you want the meaning to be?\n• Are you on track?\n• What would need to change?', NULL, '{}', 'purpose', 'feeling', '{answered_20+}', 'life_meaning', '{purpose,legacy}', 461),
(4, 'What scene from your life would you insist a movie get exactly right?\n---\nOne scene, no compromises.\n• A conversation, a quiet moment, a turning point\n• Only you know its full weight\n• Why that one?', NULL, '{}', 'pivotal', 'event', '{answered_20+}', 'must_get_right', '{pivotal,truth}', 462),
(4, 'What feeling do you hope your loved ones carry of you?\n---\nNot facts, the feeling of you.\n• Something you said, did, or a way you made them feel\n• What do you hope they remember most?\n• Is it something you can still give them?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'remembered_for', '{legacy,love}', 463),
(4, 'What question would you most want answered?\n---\nOne thing you could know with certainty.\n• About your family''s past, someone''s feelings, what comes next\n• What would it be?\n• Why that one?', NULL, '{}', 'mystery', 'feeling', '{answered_20+}', 'unanswered_question', '{mystery,curiosity}', 464),
(4, 'What would your life sound like told with maximum compassion?\n---\nTell it with kindness.\n• What would you forgive yourself for?\n• What would you celebrate?\n• What would be different?', NULL, '{}', 'compassion', 'feeling', '{answered_20+}', 'kindest_version', '{compassion,self_love}', 465),
(4, 'What contradiction in your personality have you made peace with?\n---\nWe all contain opposites.\n• Shy and bold, structured and chaotic\n• What''s the contradiction?\n• How did you stop fighting it?', NULL, '{}', 'acceptance', 'feeling', '{answered_20+}', 'accepted_contradiction', '{acceptance,wholeness}', 466),
(4, 'What wisdom did you earn the hard way that you hope someone else learns gently?\n---\nHard-won knowledge deserves sharing.\n• What did the experience cost?\n• What did it teach?\n• How would you pass it on?', NULL, '{}', 'teaching', 'feeling', '{answered_20+}', 'hard_won_wisdom', '{teaching,generosity}', 467),
(4, 'How much of your life has actually been about love, even the parts that didn''t look like it?\n---\nLove drives more than we admit.\n• Tough decisions, sacrifices, silent years\n• What does the full picture look like?\n• What surprises you about it?', NULL, '{}', 'love', 'feeling', '{answered_20+}', 'love_through_all', '{love,reframing}', 468),
(4, 'If someone had five minutes to understand who you really are, what should they know?\n---\nNot biography, the essential truth.\n• What''s the five-minute version of you?\n• What would you include?\n• What would you leave out?', NULL, '{}', 'essence', 'feeling', '{answered_20+}', 'five_minutes', '{essence,priority}', 469),
(4, 'What one thing do you want your loved ones to truly understand about your life?\n---\nThe thing you''ve struggled most to communicate.\n• What is it?\n• Why does it matter so much?\n• What would change if they got it?', NULL, '{}', 'communication', 'feeling', '{answered_20+}', 'guarantee_understood', '{communication,legacy}', 470),
(4, 'What line connects the child you were to the person you are now?\n---\nSomething survived every change.\n• Curiosity, stubbornness, tenderness\n• What''s the throughline?\n• What did you carry from then to now?', NULL, '{}', 'continuity', 'turning_point', '{answered_20+}', 'child_to_adult', '{continuity,identity}', 471),
(4, 'How does your life compare to what you expected it would be?\n---\nExpectations and reality rarely match.\n• Where did reality fall short, exceed, or surprise?\n• What surprises you most?\n• Which version do you prefer?', NULL, '{}', 'expectations', 'feeling', '{answered_20+}', 'expectations_vs_reality', '{expectations,acceptance}', 472),
(4, 'What''s the bravest thing about the way you''ve lived your life?\n---\nNot a single moment, the sustained courage.\n• Choosing love, staying honest, refusing to give up\n• What would you give yourself credit for?\n• Does anyone else see it?', NULL, '{}', 'courage', 'feeling', '{answered_20+}', 'bravest_life', '{courage,pride}', 473),
(4, 'What were you put here to learn?\n---\nThe curriculum of a life.\n• Patience, forgiveness, joy, letting go\n• Have you figured it out?\n• Or still in the middle of the lesson?', NULL, '{}', 'purpose', 'feeling', '{answered_20+}', 'here_to_learn', '{purpose,spiritual}', 474),
(4, 'What pattern in your memories hadn''t you noticed before?\n---\nLooking back reveals new connections.\n• Belonging, independence, showing up for people\n• What''s emerging?\n• What surprises you?', NULL, '{}', 'discovery', 'turning_point', '{answered_20+}', 'new_pattern', '{discovery,awareness}', 475),
(4, 'What would you tell someone going through your hardest experience?\n---\nNot platitudes, the honest earned truth.\n• What do you know from living through it?\n• What words would actually help?\n• What do you wish someone had said?', NULL, '{}', 'advice', 'feeling', '{answered_20+}', 'hindsight_advice', '{advice,empathy}', 476),
(4, 'What important thing almost didn''t happen in your life?\n---\nSome pivotal moments nearly miss us.\n• A relationship, a decision, a stroke of luck\n• What was it?\n• What does your life look like without it?', NULL, '{}', 'fate', 'event', '{answered_20+}', 'almost_didnt', '{fate,gratitude}', 477),
(4, 'How do you want to be loved for the rest of your life?\n---\nWhat you need changes over time.\n• Different from twenty, different from ten years ago\n• What does love look like in this chapter?\n• Have you told anyone?', NULL, '{}', 'love', 'feeling', '{answered_20+}', 'future_love', '{love,desire}', 478),
(4, 'What question keeps circling back no matter how many times you try to answer it?\n---\nSome questions are lifelong companions.\n• What is it?\n• How long have you been carrying it?\n• Are you any closer?', NULL, '{}', 'obsession', 'feeling', '{answered_20+}', 'recurring_question', '{obsession,meaning}', 479),
(4, 'What would the most generous assumption about your life look like?\n---\nKindest possible eyes on your choices and struggles.\n• What would they see?\n• What story would generosity tell?\n• Could you believe it?', NULL, '{}', 'grace', 'feeling', '{answered_20+}', 'generous_assumption', '{grace,perspective}', 480),
(4, 'What surprises you most about who you''ve become?\n---\nYounger you had different predictions.\n• The biggest surprise\n• Pleased with it, or still adjusting?\n• What would you tell them?', NULL, '{}', 'surprise', 'turning_point', '{answered_20+}', 'self_surprise', '{surprise,evolution}', 481),
(4, 'What three truths would you pass down to the next generation?\n---\nNot objects, values or ways of being.\n• What matters enough to survive you?\n• What three things would you want to outlast?\n• Why those?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'three_things', '{legacy,curation}', 482),
(4, 'What''s the most beautiful ordinary thing in your life right now?\n---\nNot a vacation or milestone, just a regular part of your days.\n• Something genuinely lovely if you stop and notice\n• What is it?\n• When did you last pause to appreciate it?', NULL, '{}', 'gratitude', 'feeling', '{answered_20+}', 'beautiful_ordinary', '{gratitude,present}', 483),
(4, 'If you wrote a love letter to your own life, what would it say?\n---\nA thank-you note to the whole messy experience of being you.\n• What are you grateful for that you rarely name?\n• What would you forgive?\n• What would you celebrate?', NULL, '{}', 'self_love', 'feeling', '{answered_20+}', 'love_letter_life', '{self_love,gratitude}', 484),
(4, 'What sentence would you want on the last page of your story?\n---\nNot an epitaph, a closing line.\n• Captures the tone, the lesson, the feeling\n• What would end it right?\n• Take your time', NULL, '{}', 'endings', 'feeling', '{answered_20+}', 'last_page', '{endings,meaning}', 485),
(4, 'What do all the people you''ve loved have in common?\n---\nPatterns in love reveal deep truths.\n• A quality, a way of being, a feeling they gave you\n• What''s the pattern?\n• What does it tell you about what you need?', NULL, '{}', 'patterns', 'people', '{answered_20+}', 'love_pattern', '{patterns,attraction}', 486),
(4, 'What does a good day look like at this point in your life?\n---\nThe definition changes over time.\n• Used to require excitement, now requires stillness, or vice versa\n• What does it look like now?\n• What does the shift reveal?', NULL, '{}', 'evolution', 'event', '{answered_20+}', 'good_day_now', '{evolution,simplicity}', 487),
(4, 'What have you built that you''re proudest of?\n---\nNot something you can hold in your hands.\n• A life, a family, a reputation, a way of being\n• What is it, how long has it taken?\n• What did it require?', NULL, '{}', 'pride', 'feeling', '{answered_20+}', 'proudest_built', '{pride,creation}', 488),
(4, 'What is your relationship with hope like right now?\n---\nHope evolves as we do.\n• More hopeful, more cautious, completely different\n• What does hope mean at this stage?\n• Where do you find it?', NULL, '{}', 'hope', 'feeling', '{answered_20+}', 'hope_relationship', '{hope,evolution}', 489),
(4, 'What song would play over the closing credits of your life?\n---\nChoose the mood you want to leave.\n• What would it be, why that one?\n• Would people be surprised?\n• What feeling does it capture?', NULL, '{}', 'music', 'feeling', '{answered_20+}', 'closing_song', '{music,tone}', 490),
(4, 'What do you still want to become?\n---\nNot achieve, become.\n• A quality, a way of being, a version still forming\n• What is it?\n• What will it take to get there?', NULL, '{}', 'aspiration', 'feeling', '{answered_20+}', 'still_becoming', '{aspiration,future}', 491),
(4, 'What was your greatest act of faith?\n---\nReligious or otherwise.\n• Trusting a person, taking a leap, believing the unprovable\n• What was the act, what were you risking?\n• How did it change you?', NULL, '{}', 'faith', 'event', '{answered_20+}', 'greatest_faith', '{faith,leap}', 492),
(4, 'What part of your story can only you tell?\n---\nSome perspectives are irreplaceable.\n• A truth inside your experience alone\n• A piece of history that dies with you if unshared\n• What makes your telling essential?', NULL, '{}', 'uniqueness', 'feeling', '{answered_20+}', 'only_you', '{uniqueness,authority}', 493),
(4, 'What would you want future people to know about what it was like to live now?\n---\nNot the news, the texture of daily life.\n• Small pleasures, particular worries\n• Things that won''t make it into history books\n• What would you preserve?', NULL, '{}', 'witness', 'event', '{answered_20+}', 'era_witness', '{witness,history}', 494),
(4, 'If your life had a thesis statement, what would it be?\n---\nOne argument your life has been making all along.\n• Underneath all the noise, changes, and detours\n• What has your life been trying to say?\n• When did you first hear it?', NULL, '{}', 'synthesis', 'feeling', '{answered_20+}', 'thesis_statement', '{synthesis,distillation}', 495),
(4, 'What''s the most important conversation you''ve had with yourself?\n---\nSelf-talk shapes our lives.\n• During a walk, in the mirror, in the middle of the night\n• What did you need to tell yourself?\n• Did you listen?', NULL, '{}', 'introspection', 'event', '{answered_20+}', 'self_conversation', '{introspection,growth}', 496),
(4, 'After everything, what do you know for sure?\n---\nAll the stories, people, places, choices.\n• Not what you believe or hope\n• What you know in your bones\n• What is it?', NULL, '{}', 'certainty', 'feeling', '{answered_20+}', 'know_for_sure', '{certainty,wisdom}', 497),
(4, 'What has been the most unexpected gift of your life?\n---\nSome gifts arrive uninvited.\n• Something you never would have chosen\n• A detour that became the main road\n• What makes it remarkable?', NULL, '{}', 'gratitude', 'feeling', '{answered_20+}', 'unexpected_gift', '{gratitude,surprise}', 498),
(4, 'What has your life really been about?\n---\nNot the plan, the real thing underneath.\n• Strip away noise, expectations, distractions\n• What was it really about?\n• When did you first see it?', NULL, '{}', 'truth', 'turning_point', '{answered_20+}', 'actually_about', '{truth,honesty}', 499),
(4, 'Close your eyes. Feel the weight and warmth of your whole story. What do you feel?\n---\nDon''t organize or judge, just feel it.\n• Everything remembered and still hidden\n• The whole life, the whole you\n• What comes?', NULL, '{}', 'summation', 'feeling', '{answered_20+}', 'final_feeling', '{summation,wholeness}', 500);
